function parseDiffStats(text) {
  const added = Number(text.match(/\\+(\\d+)(?:\\s*line)?/i)?.[1] || 0);
  const removed = Number(text.match(/(?:^|\\s)-(\\d+)(?:\\s*line)?/im)?.[1] || 0);
  return { added, removed };
}

