const ROLE_COLORS = { researcher: '#3B82F6', skeptic: '#8B5CF6', synthesizer: '#10B981', reviewer: '#8B5CF6', coder: '#10B981', planner: '#3B82F6', docs: '#EC4899', test: '#F59E0B' };
