function renderDataRootStatus(dataRoot) {
  const root = dataRoot?.root || state.snapshot?.settings?.dataRoot?.root || '';
  const entries = dataRoot?.summary?.entries;
  const bytes = dataRoot?.summary?.bytes;
  const summary = entries == null
    ? 'Local projects, sessions, runtime configs, MCP, teams, workflows, and settings.'
    : String(entries) + ' items, ' + formatFileSize(bytes || 0) + '. Old data is kept after migration.';
  const pathEl = el('settingsDataRootPath');
  const summaryEl = el('settingsDataRootSummary');
  if (pathEl) pathEl.textContent = root || 'Data root unavailable';
  if (summaryEl) summaryEl.textContent = summary;
}
async function refreshDataRootSettings() {
  renderDataRootStatus(state.snapshot?.settings?.dataRoot);
  try {
    const res = await api('/api/settings/data-root');
    if (!res.ok) return;
    renderDataRootStatus(await res.json());
  } catch {
    // Keep the state snapshot value.
  }
}
async function changeDataRootFromSettings() {
  const targetRoot = await pickFolderViaApi();
  if (!targetRoot) return;
  let current = null;
  try {
    const res = await api('/api/settings/data-root');
    if (res.ok) current = await res.json();
  } catch { /* preview is optional */ }
  const entries = current?.summary?.entries ?? 0;
  const bytes = current?.summary?.bytes ?? 0;
  const contents = Array.isArray(current?.contents) ? current.contents : [];
  const confirmed = window.confirm([
    'Move Actoviq data storage?',
    '',
    'From:',
    current?.root || state.snapshot?.settings?.dataRoot?.root || '(current data root)',
    '',
    'To:',
    targetRoot,
    '',
    'Will copy ' + entries + ' items (' + formatFileSize(bytes) + '). Old data will be kept.',
    contents.length ? 'Includes: ' + contents.slice(0, 12).join(', ') + (contents.length > 12 ? ', …' : '') : '',
  ].join('\\n'));
  if (!confirmed) return;
  const status = el('settingsStatus');
  if (status) status.textContent = 'Migrating data...';
  const res = await api('/api/settings/data-root', {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify({ targetRoot, confirmed: true }),
  });
  const payload = await res.json();
  if (!res.ok) {
    if (status) status.textContent = payload.error || 'Migration failed';
    return;
  }
  if (payload.state) {
    state.snapshot = payload.state;
    applyLoadedState();
    applyPreferences(state.snapshot.settings?.preferences);
  } else {
    await loadState();
  }
  renderDataRootStatus(payload.dataRoot || state.snapshot?.settings?.dataRoot);
  if (status) status.textContent = payload.changed === false ? 'Data root unchanged' : 'Data root migrated';
}
async function openSettings(tab = 'general') {
  // Always fetch fresh state so the bridge config list / runtime discovery
  // reflect configs added since the last loadState (the cached snapshot can
  // be stale, which previously made the Models tab show "No saved configs"
  // even when ~/.actoviq/bridge-configs.json had entries).
  await loadState();
  const settings = state.snapshot?.settings || {};
  const preferences = settings.preferences || {};
  el('settingsPath').textContent = settings.configPath ? 'Saved locally: ' + settings.configPath : 'Settings path unavailable';
  renderDataRootStatus(settings.dataRoot);
  void refreshDataRootSettings();
  const mode = preferences.workMode === 'daily' ? 'daily' : 'coding';
  setChecked('settingsWorkModeCoding', mode === 'coding');
  setChecked('settingsWorkModeDaily', mode === 'daily');
  setField('settingsProvider', settings.provider || 'anthropic');
  setField('settingsDefaultModel', settings.defaultModel || '');
  setField('settingsApiKey', '');
  el('settingsApiKey').placeholder = settings.apiKeyConfigured ? 'Configured; leave blank to keep current key' : 'Paste API key';
  setChecked('settingsClearApiKey', false);
  setField('settingsBaseUrl', settings.baseURL || '');
  setField('settingsPermissionPreset', '');
  setChecked('settingsDefaultPermission', true);
  setChecked('settingsAutoAudit', state.snapshot?.permissionMode === 'acceptEdits');
  setChecked('settingsFullAccess', state.snapshot?.permissionMode === 'bypassPermissions');
  setField('settingsMinModel', settings.minModel || '');
  setField('settingsMediumModel', settings.mediumModel || '');
  setField('settingsMaxModel', settings.maxModel || '');
  setField('settingsEffort', '');
  setField('settingsTheme', preferences.theme || 'system');
  setField('settingsDensity', preferences.density || 'comfortable');
  setChecked('settingsEnterToSend', preferences.enterToSend);
  setChecked('settingsAutoScroll', preferences.autoScroll !== false);
  setChecked('settingsDeveloperTools', preferences.developerTools === true);
  setChecked('settingsShowBranchInComposer', preferences.showBranchInComposer !== false);
  setField('settingsOutputStyle', preferences.outputStyle || state.snapshot?.outputStyle || 'default');
  renderBridgeConfigs();
  renderMcpServers();
  renderShortcutsPanel();
  el('settingsStatus').textContent = '';
  renderSettingsCommandPanels();
  el('settingsModal').classList.remove('hidden');
  showSettingsTab(tab);
}
function closeSettings() { el('settingsModal').classList.add('hidden'); }
function derivePermissionPreset() {
  if (el('settingsPermissionPreset').value) return el('settingsPermissionPreset').value;
  if (el('settingsFullAccess').checked) return 'full';
  if (el('settingsAutoAudit').checked) return 'workspace';
  if (el('settingsDefaultPermission').checked) return 'workspace';
  return '';
}
let settingsAutosaveTimer = null;
let settingsAutosaveSeq = 0;
function collectSettingsBody() {
  const workMode = document.querySelector('input[name="settingsWorkMode"]:checked')?.value || 'coding';
  return {
    provider: el('settingsProvider').value,
    defaultModel: el('settingsDefaultModel').value,
    apiKey: el('settingsApiKey').value,
    clearApiKey: el('settingsClearApiKey').checked,
    baseURL: el('settingsBaseUrl').value,
    permissionPreset: derivePermissionPreset(),
    minModel: el('settingsMinModel').value,
    mediumModel: el('settingsMediumModel').value,
    maxModel: el('settingsMaxModel').value,
    effort: el('settingsEffort').value,
    preferences: {
      workMode,
      theme: el('settingsTheme').value,
      density: el('settingsDensity').value,
      enterToSend: el('settingsEnterToSend').checked,
      autoScroll: el('settingsAutoScroll').checked,
      developerTools: el('settingsDeveloperTools').checked,
      outputStyle: el('settingsOutputStyle')?.value || 'default',
      showBranchInComposer: el('settingsShowBranchInComposer')?.checked !== false,
    },
  };
}
async function persistSettingsNow() {
  const seq = ++settingsAutosaveSeq;
  const status = el('settingsStatus');
  if (status) status.textContent = 'Saving…';
  try {
    const res = await api('/api/settings', {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify(collectSettingsBody()),
    });
    if (seq !== settingsAutosaveSeq) return;
    if (!res.ok) {
      if (status) status.textContent = 'Save failed';
      addMessage('error', await res.text());
      return;
    }
    state.snapshot = await res.json();
    applyPreferences(state.snapshot.settings?.preferences);
    if (status) {
      status.textContent = state.snapshot.settingsApplyError ? 'Saved; restart may be required' : 'Saved';
    }
    if (state.snapshot.settingsApplyError) {
      addMessage('notice', 'Settings saved, but the active SDK could not reload: ' + state.snapshot.settingsApplyError);
    }
    // Clear API key field after a successful save so we don't re-send it.
    if (el('settingsApiKey').value) {
      setField('settingsApiKey', '');
      el('settingsApiKey').placeholder = 'Configured; leave blank to keep current key';
      setChecked('settingsClearApiKey', false);
    }
    await loadState();
    if (seq !== settingsAutosaveSeq) return;
    if (!el('settingsModal').classList.contains('hidden')) renderSettingsCommandPanels();
    if (status && status.textContent === 'Saved') {
      setTimeout(() => {
        if (settingsAutosaveSeq === seq && status.textContent === 'Saved') status.textContent = '';
      }, 1600);
    }
  } catch (error) {
    if (seq !== settingsAutosaveSeq) return;
    if (status) status.textContent = 'Save failed';
    addMessage('error', error?.message || String(error));
  }
}
function scheduleSettingsAutosave(delayMs = 450) {
  if (settingsAutosaveTimer) clearTimeout(settingsAutosaveTimer);
  settingsAutosaveTimer = setTimeout(() => {
    settingsAutosaveTimer = null;
    void persistSettingsNow();
  }, delayMs);
}
function wireSettingsAutosave() {
  const form = el('settingsForm');
  if (!form || form.dataset.autosaveWired === '1') return;
  form.dataset.autosaveWired = '1';
  form.addEventListener('submit', (event) => {
    event.preventDefault();
    if (settingsAutosaveTimer) clearTimeout(settingsAutosaveTimer);
    settingsAutosaveTimer = null;
    void persistSettingsNow();
  });
  form.addEventListener('change', (event) => {
    const target = event.target;
    if (!target || !target.id || !String(target.id).startsWith('settings')) return;
    // Schedule/team fields have their own APIs. Output style persists via preferences + /output-style.
    if (target.id.startsWith('settingsSchedule')) return;
    if (target.id.startsWith('settingsTeam')) return;
    if (target.id === 'settingsOutputStyle') {
      submitText('/output-style ' + target.value);
      scheduleSettingsAutosave(120);
      return;
    }
    // Immediate for toggles/selects; text fields debounce via input.
    const tag = String(target.tagName || '').toLowerCase();
    const type = String(target.type || '').toLowerCase();
    if (tag === 'select' || type === 'checkbox' || type === 'radio') scheduleSettingsAutosave(120);
    else scheduleSettingsAutosave(450);
  });
  form.addEventListener('input', (event) => {
    const target = event.target;
    if (!target || !target.id || !String(target.id).startsWith('settings')) return;
    if (target.id === 'settingsOutputStyle') return;
    if (target.id.startsWith('settingsSchedule')) return;
    if (target.id.startsWith('settingsTeam')) return;
    const tag = String(target.tagName || '').toLowerCase();
    const type = String(target.type || '').toLowerCase();
    if (tag === 'select' || type === 'checkbox' || type === 'radio') return;
    scheduleSettingsAutosave(450);
  });
}
